 1	import type { FC } from 'react';
 2	
 3	import { Switch } from '@patternfly/react-core';
 4	import { useForkliftTranslation } from '@utils/i18n';
 5	
 6	type LiveSwitchProps = {
 7	  onChange: (checked: boolean) => void;
 8	  value: boolean;
 9	};
10	
11	const LiveSwitch: FC<LiveSwitchProps> = ({ onChange, value }) => {
12	  const { t } = useForkliftTranslation();
13	  return (
14	    <Switch
15	      label={t(
16	        'Live migration, the source virtual machines continue running while their state is synchronized with the destination.',
17	      )}
18	
19	
20	
21	      isChecked={value}
22	      onChange={(_, checked) => {
23	        onChange(checked);
24	      }}
25	    />
26	  );
27	};
28	
29	export default LiveSwitch;

